// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  category: CategoryStore
  medicine: MedicineStore
  address: AddressStore
  cartItem: CartItemStore
  order: OrderStore
  orderItem: OrderItemStore
  prescription: PrescriptionStore
  wishlist: WishlistStore
  coupon: CouponStore
  otpVerification: OtpVerificationStore

  constructor() {
    this.user = new UserStore()
    this.category = new CategoryStore()
    this.medicine = new MedicineStore()
    this.address = new AddressStore()
    this.cartItem = new CartItemStore()
    this.order = new OrderStore()
    this.orderItem = new OrderItemStore()
    this.prescription = new PrescriptionStore()
    this.wishlist = new WishlistStore()
    this.coupon = new CouponStore()
    this.otpVerification = new OtpVerificationStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.category.clear()
    this.medicine.clear()
    this.address.clear()
    this.cartItem.clear()
    this.order.clear()
    this.orderItem.clear()
    this.prescription.clear()
    this.wishlist.clear()
    this.coupon.clear()
    this.otpVerification.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
